PREFIX wdt: <http://www.wikidata.org/prop/direct/>
SELECT ?date WHERE {
  ?person wdt:P31 wd:Q5;
          wdt:P20 ?deathLocation;
          wdt:P570 ?date;
          wdt:P2068 ?method.
  ?deathLocation wdt:P131* wd:Q812.
}
ORDER BY DESC(?date)
LIMIT 1

